import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import './Pages.css';

const KatthaAccounts = () => {
  const [language, setLanguage] = useState('en');
  const [accounts, setAccounts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});

  const translations = {
    en: { katthaAccounts: 'Kattha Accounts', balance: 'Balance', lastPurchase: 'Last Purchase', 
      status: 'Status', noData: 'No accounts', edit: 'Edit', delete: 'Delete', save: 'Save', cancel: 'Cancel' },
    te: { katthaAccounts: 'ఖత్తా ఖాతాలు', balance: 'బ్యాలెన్స్', lastPurchase: 'చివరి కొనుగోలు', 
      status: 'స్థితి', noData: 'ఖాతాలు లేవు', edit: 'సవరించు', delete: 'తొలగించు', save: 'సేవ్', cancel: 'రద్దు' },
    hi: { katthaAccounts: 'खता खाते', balance: 'शेष', lastPurchase: 'अंतिम खरीद', 
      status: 'स्थिति', noData: 'कोई खाता नहीं', edit: 'संपादित करें', delete: 'हटाएं', save: 'सेव करें', cancel: 'रद्द करें' }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchAccounts();
  }, []);

  const fetchAccounts = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/pending', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setAccounts(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (account) => {
    setEditingId(account._id);
    setEditData({
      customerName: account.customerName,
      pendingBalance: account.pendingBalance
    });
  };

  const handleSave = async (id) => {
    try {
      const token = localStorage.getItem('token');
      await axios.put(`http://localhost:5000/api/accounts/${id}`, editData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setEditingId(null);
      fetchAccounts();
    } catch (err) {
      console.error('Error saving:', err);
    }
  };

  const handleCancel = () => {
    setEditingId(null);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this account?')) {
      try {
        const token = localStorage.getItem('token');
        await axios.delete(`http://localhost:5000/api/accounts/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchAccounts();
      } catch (err) {
        console.error('Error deleting:', err);
      }
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />
      <div className="main-content">
        <div className="top-bar">
          <h1>{t.katthaAccounts}</h1>
          <select value={language} onChange={(e) => setLanguage(e.target.value)} className="language-selector">
            <option value="en">English</option>
            <option value="te">Telugu</option>
            <option value="hi">Hindi</option>
          </select>
        </div>

        <div className="page-card">
          {loading ? (
            <p>Loading...</p>
          ) : accounts.length === 0 ? (
            <p className="no-data">{t.noData}</p>
          ) : (
            <table className="bills-table">
              <thead>
                <tr>
                  <th>Customer</th>
                  <th>{t.balance}</th>
                  <th>{t.lastPurchase}</th>
                  <th>{t.status}</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {accounts.map(account => (
                  <tr key={account._id}>
                    <td>
                      {editingId === account._id ? (
                        <input
                          type="text"
                          value={editData.customerName}
                          onChange={(e) => setEditData({ ...editData, customerName: e.target.value })}
                        />
                      ) : (
                        account.customerName
                      )}
                    </td>
                    <td>
                      {editingId === account._id ? (
                        <input
                          type="number"
                          value={editData.pendingBalance}
                          onChange={(e) => setEditData({ ...editData, pendingBalance: parseFloat(e.target.value) })}
                        />
                      ) : (
                        `₹ ${account.pendingBalance?.toFixed(2)}`
                      )}
                    </td>
                    <td>{new Date(account.lastPurchaseDate).toLocaleDateString()}</td>
                    <td><span className="status open">OPEN</span></td>
                    <td>
                      {editingId === account._id ? (
                        <>
                          <button onClick={() => handleSave(account._id)}>{t.save}</button>
                          <button onClick={handleCancel}>{t.cancel}</button>
                        </>
                      ) : (
                        <>
                          <button onClick={() => handleEdit(account)}>{t.edit}</button>
                          <button onClick={() => handleDelete(account._id)}>{t.delete}</button>
                        </>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default KatthaAccounts;
